values
  ('settings', '{"siteName":"Sabdia Constructions","legalName":"Sabdia Constructions Pty Ltd","estYear":2013,"logo":"https://static.wixstatic.com/media/1cc2db_f012027bbf0c45ebb4ae6d847309d59f~mv2.png/v1/fill/w_211,h_35,al_c,q_85,usm_0.66_1.00_0.01,enc_avif,quality_auto/DESIGN%20%C2%B7%20DEVELOP%20%C2%B7%20CONSTRUCT.png","logoLarge":"https://static.wixstatic.com/media/1cc2db_f012027bbf0c45ebb4ae6d847309d59f~mv2.png/v1/fill/w_422,h_70,al_c,q_85,usm_0.66_1.00_0.01,enc_avif,quality_auto/DESIGN%20%C2%B7%20DEVELOP%20%C2%B7%20CONSTRUCT.png","location":"Brisbane, Queensland, Australia","email":"sales@sabdia.com.au","phone":"","domainDisplay":"sabdiaconstructions.com.au","domainUrl":"https://www.sabdiaconstructions.com.au","socials":{"instagram":{"label":"@_sabdia","url":"https://www.instagram.com/_sabdia/"},"facebook":{"label":"Sabdia Constructions","url":"https://www.facebook.com/sabdiaconstructions/"},"linkedin":{"label":"Sabdia Constructions","url":"https://www.linkedin.com/company/sabdia-constructions/"}},"seo":{"title":"Sabdia Constructions | Luxury Home Builders & Developers, Brisbane","description":"Boutique luxury home builder and developer in inner Brisbane. Multi-award winning, 100+ residences delivered since 2013. Design, Develop, Construct.","ogTitle":"Sabdia Constructions — Luxury Home Builders, Brisbane","ogDescription":"Boutique luxury home builder and developer in inner Brisbane. Multi-award winning, 100+ residences delivered since 2013.","ogImage":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg/v1/fill/w_1200,h_630,al_c,q_85/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg"},"jsonLdImage":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg","jsonLdDescription":"Boutique luxury home builder and developer in inner Brisbane. Multi-award winning, 100+ residences delivered since 2013.","areaServed":"Brisbane, Queensland, Australia"}'::jsonb),
