  ('footer', '{"taglineHtml":"Design. <em>Develop.</em><br>Construct.","taglineSub":"Boutique luxury home builder & developer delivering award-winning residences across inner Brisbane since 2013.","blurbHtml":"Boutique Luxury Home Builder &<br>Developer — Brisbane, QLD","companyLinks":[{"label":"About Sabdia","href":"/about/"},{"label":"Services","href":"/services/"},{"label":"Projects","href":"/projects/"},{"label":"Collection","href":"/collection/"},{"label":"Agent Access","href":"/agent-access/"}],"legalLinks":[{"label":"Accessibility","href":"/accessibility/"},{"label":"Privacy","href":"/privacy/"}]}'::jsonb),
  ('home_hero', '{"words":["Design","Develop","Construct"],"eyebrow":"Boutique Luxury Home Builder & Developer — Brisbane","description":"Redefining luxury through design, detail, and craftsmanship. For over ten years, Sabdia has delivered award-winning residences that set a new benchmark for contemporary living in Brisbane.","award":"Award-Winning Luxury Residences.","slides":[{"image":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg","alt":"Sabdia luxury home"},{"image":"https://static.wixstatic.com/media/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg","alt":"Sabdia luxury home"},{"image":"https://static.wixstatic.com/media/1cc2db_5186783e26c04be6ab983f26b9b78377~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_5186783e26c04be6ab983f26b9b78377~mv2.jpg","alt":"Sabdia luxury home"}],"primaryCta":{"label":"View Properties","href":"/properties/"},"secondaryCta":{"label":"Begin a Conversation","href":"/contact/"}}'::jsonb),
  ('home_stats', '{"items":[{"target":10,"suffix":"+","label":"Years in Brisbane","count":true},{"target":100,"suffix":"+","label":"Residences Delivered","count":true},{"target":5,"suffix":"★","label":"Multi-Award Winning","count":true},{"target":100,"suffix":"%","label":"In-House Delivery","count":false}]}'::jsonb),
  ('home_marquee', '{"items":["Multi-Award Winning","Design · Develop · Construct","Inner Brisbane Specialist","100+ Residences Since 2013","Boutique Luxury Developer"]}'::jsonb),
  ('home_about', '{"label":"About Sabdia","headingHtml":"Crafting <em>Exquisite</em><br>Living Spaces.","images":[{"image":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg/v1/fill/w_900,h_600,al_c,q_85/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg","alt":"Sabdia craftsmanship"},{"image":"https://static.wixstatic.com/media/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg/v1/fill/w_500,h_600,al_c,q_85/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg","alt":"Sabdia detail"}],"paragraphs":["At Sabdia, we manage every step of the residential development journey in-house — from visionary design through to expert construction. This integrated approach allows us to maintain meticulous control over quality, timing, and innovation, delivering homes that stand the test of time.","With a focus on creating exceptional living spaces, Sabdia Constructions is dedicated to shaping the future of residential developments through innovation, quality, and unparalleled craftsmanship. Every project begins with a deep understanding of both the site and the clients who will call it home.","We are not merely builders — we are creators of legacy. Each residence we deliver is conceived as a singular work of architecture, thoughtfully designed to complement its surroundings and exceed every expectation of luxury living."],"sigName":"Sabdia","sigTitle":"Founder & Principal","values":[{"n":"i.","title":"Integrated Delivery","desc":"Design, develop, and construct under one roof — seamless from concept to keys."},{"n":"ii.","title":"Uncompromising Quality","desc":"Only the finest materials, master tradespeople, and meticulous attention to detail."},{"n":"iii.","title":"Boutique & Personal","desc":"Limited projects annually to ensure every client receives our full dedication."}],"cta":{"label":"Our Full Story","href":"/about/"}}'::jsonb),
  ('home_properties', '{"label":"For Sale","headingHtml":"<em>Current</em> Properties","cta":{"label":"View All","href":"/properties/"}}'::jsonb),
  ('home_services', '{"label":"What We Do","headingHtml":"Full-spectrum<br><em>development</em><br>expertise.","text":"From site acquisition through to final handover, Sabdia manages every element in-house — ensuring seamless delivery and uncompromising quality at every stage.","cta":{"label":"Explore Services","href":"/services/"}}'::jsonb),
  ('home_process', '{"label":"Our Process"}'::jsonb),
  ('home_agent', '{"label":"For Real Estate Professionals","headingHtml":"Exclusive <em>Agent</em><br>Access.","text":"Gain exclusive insight into Sabdia''s future releases. Our agent-only preview list offers early access to premium developments, pre-launch information, and priority communication — giving your clients an edge in Brisbane''s luxury market.","badge":"Exclusive Access","image":{"image":"https://static.wixstatic.com/media/1cc2db_7d6ddb5093af4f3eb6b9d3acd088be79~mv2.png/v1/fill/w_900,h_1100,q_85,enc_avif,quality_auto/1cc2db_7d6ddb5093af4f3eb6b9d3acd088be79~mv2.png","alt":"Agent Access"},"features":["Pre-release access to upcoming developments","Pre-launch pricing and floor plan information","Priority communication on new releases","Exclusive commission structures","Invitations to private project previews","Dedicated liaison with the Sabdia team"],"primaryCta":{"label":"Apply for Access","href":"/agent-access/"},"secondaryCta":{"label":"Learn More","href":"/contact/"}}'::jsonb),
  ('home_contact', '{"label":"Get In Touch","headingHtml":"Let''s start<br>a <em>conversation</em>.","text":"Please submit your contact information and one of our team members will be in touch with you shortly.","interests":["For Sale — Current Properties","Custom Home Design","Development Partnership","Agent Access","General Enquiry"],"note":"We typically respond within one business day."}'::jsonb),
  ('films', '{"brand":{"label":"The Sabdia Story","headingHtml":"Crafted moments,<br><em>captured on film</em>.","text":"A look at the residences, the craftsmanship, and the people behind every Sabdia home.","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/brand.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/brand-poster.jpg"},"sectionLabel":"The Film","byProperty":{"qasr":{"video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/qasr.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/qasr-poster.jpg"},"solace":{"video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/solace.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/solace-poster.jpg"},"sierra":{"video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/sierra.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/sierra-poster.jpg"},"capri":{"video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/capri.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/capri-poster.jpg"},"aether":{"video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/aether.mp4","poster":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/aether-poster.jpg"}}}'::jsonb),
  ('properties_page', '{"label":"For Sale","headingHtml":"<em style=\"color:var(--gold)\">Current</em><br>Properties.","introTemplate":"{count} extraordinary residences across Brisbane''s most sought-after inner suburbs — each designed, developed, and built entirely in-house by Sabdia.","soldLabel":"Sold Prior to Completion","cta":{"label":"Private Enquiry","headingHtml":"Interested in a<br><em style=\"color:var(--gold)\">private viewing</em>?","text":"We offer private, exclusive viewings for serious buyers. Contact us to arrange an inspection at a time that suits you.","primaryCta":{"label":"Request a Viewing","href":"/contact/"},"secondaryCta":{"label":"Agent Enquiries","href":"/agent-access/"}}}'::jsonb),
  ('projects_page', '{"hero":{"image":"https://static.wixstatic.com/media/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg","label":"Portfolio","titleHtml":"Our<br><em>Projects</em>","sub":"Over 100 residences delivered across inner Brisbane''s most prestigious suburbs since 2013."},"currentLabel":"For Sale — Current","soldLabel":"Sold Prior to Completion","cta":{"label":"Interested?","headingHtml":"Ready to find your<br><em>next home</em>?","primaryCta":{"label":"View For Sale","href":"/properties/"},"secondaryCta":{"label":"Enquire Now","href":"/contact/"}}}'::jsonb),
  ('services_page', '{"hero":{"image":"https://static.wixstatic.com/media/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_9e730867446c414c9fe72c1549cb7261~mv2.jpg","label":"What We Offer","titleHtml":"Our<br><em>Services</em>","sub":"Full-spectrum residential development expertise delivered entirely in-house."},"intro":{"label":"Integrated Approach","headingHtml":"Every element,<br><em>under one roof</em>.","paragraphs":["At Sabdia, we believe the best residential developments are those where design, development, and construction work as one seamless system — not as separate, disconnected disciplines. Our fully integrated in-house model is our defining advantage.","From the first sketch to the final handover, every decision is made by the same team, with the same vision, and the same commitment to excellence."]},"processLabel":"The Process","cta":{"label":"Start Your Project","headingHtml":"Ready to build something <em style=\"color:var(--gold2)\">remarkable</em>?","text":"Whether you have a site, a vision, or simply a desire for exceptional living — we''d love to hear from you.","primaryCta":{"label":"Begin a Conversation","href":"/contact/"},"secondaryCta":{"label":"View Properties","href":"/properties/"}}}'::jsonb),
  ('about_page', '{"hero":{"image":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg/v1/fill/w_1920,h_1080,al_c,q_85/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg","label":"Our Story","titleHtml":"About<br><em>Sabdia</em>","sub":"A decade of redefining luxury residential development in inner Brisbane."},"mission":{"label":"Mission","headingHtml":"Built on <em>vision</em>,<br>delivered with<br>precision.","paragraphs":["Founded in 2013, Sabdia Constructions was born from a singular conviction: that the residential development industry in Brisbane deserved a boutique operator who refused to compromise. One that would bring together exceptional design, rigorous development management, and master-level construction under a single, unified vision.","Over a decade later, that conviction has been validated more than 100 times — in every residence we have delivered, in every client who has trusted us with their most significant investment, and in every award that has recognised our commitment to excellence.","We remain boutique by choice. By limiting the number of projects we undertake each year, we ensure that every development receives the full force of our attention, creativity, and craftsmanship. We do not build in volume. We build in detail."],"sigName":"Sabdia","sigTitle":"Founder & Principal"},"values":{"label":"Our Values","items":[{"n":"i.","title":"Integrity","desc":"We say what we do, and we do what we say. Transparency with our clients is non-negotiable at every stage of the journey."},{"n":"ii.","title":"Innovation","desc":"We push the boundaries of design and construction, constantly seeking better ways to create residences that will stand the test of time."},{"n":"iii.","title":"Excellence","desc":"We do not accept ''good enough''. Every detail, from the grandest architectural gesture to the smallest finishing touch, must be exceptional."}]},"journey":{"label":"Our Journey","headingHtml":"A decade of<br><em>milestones</em>.","text":"From a single vision to over 100 delivered residences, each year has brought new achievements and raised the bar for what luxury living in Brisbane can be.","items":[{"year":"2013","title":"Founded","desc":"Sabdia Constructions established with a vision to redefine boutique luxury residential development in inner Brisbane."},{"year":"2015","title":"First Award","desc":"Recognised with our first industry award for design excellence, validating the Sabdia approach to integrated development."},{"year":"2017","title":"50 Residences Delivered","desc":"A major milestone — 50 homes delivered to satisfied clients across inner Brisbane''s most prestigious suburbs."},{"year":"2020","title":"Interior Architecture Division","desc":"Expanded in-house capabilities to include a dedicated interior architecture team, deepening creative integration across all projects."},{"year":"2023","title":"100+ Residences","desc":"Surpassed 100 completed residences — a testament to a decade of consistency, quality, and unwavering commitment to excellence."},{"year":"2025","title":"QASR — Flagship Release","desc":"The launch of QASR, Coorparoo — Sabdia''s most ambitious and extraordinary residence to date, representing a new pinnacle of Brisbane luxury."}]},"awards":{"label":"Recognition","headingHtml":"Award-winning<br><em>excellence</em>.","items":[{"year":"2024","title":"Best Luxury Residential Development","org":"UDIA Queensland Awards"},{"year":"2023","title":"Excellence in Design","org":"HIA Australian Housing Awards"},{"year":"2022","title":"Best New Residential Development","org":"Property Council of Australia"},{"year":"2021","title":"Residential Interior Design — Luxury","org":"IDEA Awards"},{"year":"2020","title":"Custom Home of the Year — QLD","org":"Master Builders Queensland"},{"year":"2019","title":"Best Luxury Home Builder — Brisbane","org":"REIQ Awards for Excellence"}]},"cta":{"label":"Begin Your Journey","headingHtml":"Ready to create something <em>extraordinary</em>?","text":"Whether you''re seeking a current property for sale or have a vision for a bespoke home, we''d love to begin a conversation.","primaryCta":{"label":"View Properties","href":"/properties/"},"secondaryCta":{"label":"Get In Touch","href":"/contact/"}}}'::jsonb),
  ('collection_page', '{"label":"Our Work","titleHtml":"The Sabdia<br><em style=\"color:var(--gold)\">Collection</em>.","text":"A portfolio of completed luxury residences across inner Brisbane — each one designed, developed, and constructed entirely in-house by Sabdia.","items":[{"name":"MILOS","loc":"Camp Hill QLD, Australia","image":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/milos-poster.jpg","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/milos.mp4"},{"name":"AMMOS","loc":"Taringa QLD, Australia","image":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/ammos-poster.jpg","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/ammos.mp4"},{"name":"CALLE","loc":"Camp Hill QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_a11d808ebc4648de9b8a25918f19e192~mv2.png/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_a11d808ebc4648de9b8a25918f19e192~mv2.png","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/calle.mp4"},{"name":"ELYSIUM","loc":"Holland Park QLD, Australia","image":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/elysium-poster.jpg","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/elysium.mp4"},{"name":"ALHAMBRA","loc":"Brisbane QLD, Australia","image":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/alhambra-poster.jpg","video":"https://fvczsjcrvwzqtcbforgo.supabase.co/storage/v1/object/public/media/films/alhambra.mp4"},{"name":"ENCANTO","loc":"Camp Hill QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_4d7d30024fef47ba8f5f9859e08bb47b~mv2.jpeg/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_4d7d30024fef47ba8f5f9859e08bb47b~mv2.jpeg"},{"name":"NERO","loc":"Rochedale QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_9ed4e50eba3b453885aa6a4917ba5607~mv2.jpg/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_9ed4e50eba3b453885aa6a4917ba5607~mv2.jpg"},{"name":"HERMOSA","loc":"Camp Hill QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_9cbfa41ef2dd4ed3b14b5277765cc446~mv2.jpg/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_9cbfa41ef2dd4ed3b14b5277765cc446~mv2.jpg"},{"name":"FRASER","loc":"Graceville QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_fb04f5dbe53b4d34ab710537a2e24b40~mv2.jpg/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_fb04f5dbe53b4d34ab710537a2e24b40~mv2.jpg"},{"name":"PETRA","loc":"Taringa QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_64f35b15dd914a189eee2aeb79b86284~mv2.jpg/v1/fill/w_800,h_600,al_c,q_85,enc_avif,quality_auto/1cc2db_64f35b15dd914a189eee2aeb79b86284~mv2.jpg"},{"name":"KIRRA","loc":"Brisbane QLD, Australia","image":"https://static.wixstatic.com/media/1cc2db_74fc877fe2204d2a98e663d0c7df421b~mv2.png/v1/fill/w_800,h_600,fp_0.5_0.65,q_90,enc_avif,quality_auto/1cc2db_74fc877fe2204d2a98e663d0c7df421b~mv2.png"}]}'::jsonb),
  ('agent_page', '{"hero":{"image":"https://static.wixstatic.com/media/1cc2db_7d6ddb5093af4f3eb6b9d3acd088be79~mv2.png/v1/fill/w_1400,h_1800,q_85,enc_avif,quality_auto/1cc2db_7d6ddb5093af4f3eb6b9d3acd088be79~mv2.png","label":"For Real Estate Professionals","titleHtml":"Exclusive<br><em style=\"color:var(--gold2)\">Agent</em><br>Access.","text":"Join Sabdia''s exclusive agent network and be the first to know about our next landmark development before it reaches the market."},"benefits":{"label":"Why Join","headingHtml":"The Sabdia agent program gives you <em style=\"color:var(--gold2)\">a genuine edge</em>.","items":[{"icon":"layers","title":"Pre-Release Access","desc":"Be first to know about upcoming developments before they reach the public market. Give your clients a genuine first-mover advantage."},{"icon":"plan","title":"Floor Plans & Pricing","desc":"Access pre-launch floor plans and indicative pricing information exclusively — everything you need to prepare your clients before public release."},{"icon":"phone","title":"Priority Communication","desc":"A dedicated Sabdia liaison to keep you informed, respond to questions, and support you throughout the sales process."},{"icon":"dollar","title":"Exclusive Commissions","desc":"Competitive and exclusive commission structures for agent network members — recognising the value of your relationships and referrals."},{"icon":"users","title":"Private Previews","desc":"Invitations to exclusive agent-only preview events — an opportunity to walk through completed or near-complete residences before public launch."},{"icon":"star","title":"Award-Winning Product","desc":"Represent Brisbane''s most acclaimed boutique luxury developer — a brand that your clients will immediately recognise as a hallmark of quality."}]},"listings":{"label":"Current Opportunities","headingHtml":"Properties available <em>now</em>.","cta":{"label":"View All Properties","href":"/properties/"}},"apply":{"label":"Apply for Access","headingHtml":"Join the <em>network</em>.","text":"Complete the form and a member of the Sabdia team will be in touch within one business day to discuss your application and confirm your access to our exclusive agent program.","noteLabel":"Please note","noteText":"The Sabdia agent program is available to licensed real estate professionals only. We may request verification of your licence at the time of application approval.","submitLabel":"Submit Application"}}'::jsonb),
  ('contact_page', '{"hero":{"label":"Get In Touch","titleHtml":"Let''s start<br>a <em style=\"font-style:italic;color:var(--gold2)\">conversation</em>.","text":"We''re always keen to hear from potential clients, real estate professionals, and development partners. Submit your details and we''ll be in touch shortly."},"directLabel":"Direct Contact","agentBlock":{"heading":"Agent Enquiries","bodyHtml":"Real estate professionals seeking exclusive agent access — pre-launch information, priority access and commission structures — please visit our <a href=\"/agent-access/\" style=\"color:var(--gold2);text-decoration:underline;text-underline-offset:3px\">Agent Access page</a>."},"map":{"image":"https://static.wixstatic.com/media/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg/v1/fill/w_900,h_500,al_c,q_85/1cc2db_4e48586f78704fc3ae5d00ddb8a125ee~mv2.jpg","label":"Brisbane, Queensland"},"form":{"label":"Send a Message","interests":["Custom Home / Bespoke Build","Development Partnership","Agent Access","Media & Press","General Enquiry"],"submitLabel":"Submit Enquiry","note":"We respond within one business day."},"quickLinks":{"label":"You May Also Be Interested In","items":[{"tag":"For Sale","title":"Current Properties","desc":"View our current portfolio of luxury residences available for sale across Brisbane.","href":"/properties/"},{"tag":"Professionals","title":"Agent Access","desc":"Exclusive pre-launch information, priority access, and commission structures for real estate professionals.","href":"/agent-access/"},{"tag":"Company","title":"About Sabdia","desc":"Learn about our story, values, and integrated approach to boutique luxury development.","href":"/about/"}]}}'::jsonb),
  ('legal_privacy', '{"label":"Legal","titleHtml":"Privacy <em>Policy</em>.","updated":"July 2026","intro":"Sabdia Constructions Pty Ltd is committed to protecting your privacy in accordance with the Privacy Act 1988 (Cth) and the Australian Privacy Principles. This policy explains how we collect, use, and safeguard your personal information.","sections":[{"heading":"What we collect","bodyHtml":"When you submit an enquiry, register interest in a property, or apply for agent access, we collect the information you provide — typically your name, email address, phone number, and the details of your enquiry. Agent applicants may also provide their agency, licence number, and market areas. We do not collect sensitive information through this website."},{"heading":"How we use it","bodyHtml":"Your information is used solely to respond to your enquiry, keep you informed about the properties or programs you have expressed interest in, and improve our services. We do not sell, rent, or trade your personal information to third parties."},{"heading":"Storage and security","bodyHtml":"Enquiries are stored securely with our database provider and access is restricted to authorised Sabdia team members. We take reasonable steps to protect your information from misuse, interference, loss, and unauthorised access, modification, or disclosure."},{"heading":"Disclosure","bodyHtml":"We may share your information with trusted service providers who help us operate this website and communicate with you (for example, our email delivery provider). These providers are bound to handle your information only for the purpose of providing services to us."},{"heading":"Cookies and analytics","bodyHtml":"This website may use privacy-friendly analytics to understand how visitors use the site. Analytics data is aggregated and does not identify you personally."},{"heading":"Access and correction","bodyHtml":"You may request access to, or correction of, the personal information we hold about you at any time by contacting us. We will respond within a reasonable period."},{"heading":"Contact","bodyHtml":"For any privacy-related questions or requests, contact us via the enquiry form on this website or by email. If you are not satisfied with our response, you may contact the Office of the Australian Information Commissioner (OAIC)."}]}'::jsonb),
  ('legal_accessibility', '{"label":"Legal","titleHtml":"Accessibility <em>Statement</em>.","updated":"July 2026","intro":"Sabdia Constructions is committed to ensuring this website is accessible to the widest possible audience, regardless of technology or ability. We aim to conform to the Web Content Accessibility Guidelines (WCAG) 2.1 at Level AA.","sections":[{"heading":"What we do","bodyHtml":"This website is built with semantic HTML landmarks, supports full keyboard navigation with visible focus states, maintains WCAG AA colour contrast, provides descriptive alternative text for images, and respects your system''s reduced-motion preference by disabling non-essential animation."},{"heading":"Known limitations","bodyHtml":"Some third-party embedded content (such as interactive 3D models and virtual tours) may not be fully accessible. Where these features appear, the same property information is always available in accessible text form on the same page."},{"heading":"Feedback","bodyHtml":"We welcome your feedback on the accessibility of this website. If you encounter an accessibility barrier, please contact us via the enquiry form and we will make every reasonable effort to address it promptly."}]}'::jsonb),
  ('notfound', '{"label":"404","titleHtml":"This page has<br><em>moved on</em>.","text":"Like our finest residences, the page you''re looking for has found a new owner — or never existed at all. Let us guide you back.","primaryCta":{"label":"Return Home","href":"/"},"secondaryCta":{"label":"View Properties","href":"/properties/"}}'::jsonb)
